# OEIS sequence: A395926

def joey(n): return int(str(n)[1:-1]) if n > 99 else 0
def kangaroo(n): return n > 99 and (j:=joey(n)) > 0 and n%j == 0
def ok(n): return n > 99999 and kangaroo(n) and kangaroo(joey(n)) and kangaroo(joey(joey(n)))
print([k for k in range(2*10**7) if ok(k)]) # _Michael S. Branicky_, May 10 2026

